<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Bouncing Ball Playground</title>
    <style>
        body {
            background-color: #1e1e2e; /* Dark background */
            color: #cdd6f4;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 20px;
        }

        #controls {
            margin-bottom: 20px;
            display: flex;
            gap: 15px;
        }

        button {
            background-color: #45475a; /* Slightly lighter dark button */
            color: #cdd6f4;
            border: none;
            padding: 10px 20px;
            cursor: pointer;
            transition: background-color 0.2s, transform 0.1s;
            border-radius: 5px;
        }

        button:hover {
            background-color: #585b70;
        }

        button:active {
            transform: scale(0.98);
        }

        #sim {
            /* Ensure minimum size requirement is met */
            width: 400px; 
            height: 400px;
            background-color: #2e3145; /* Dark canvas background */
            border: 2px solid #6c7086;
            box-shadow: 0 4px 15px rgba(0, 0, 0, 0.5);
            cursor: crosshair;
        }

        h1 {
            color: #a6adc8;
            margin-bottom: 10px;
        }
    </style>
</head>
<body>

    <h1>Bouncing Ball Playground</h1>

    <div id="controls">
        <button id="drop">Drop Ball (Random)</button>
        <button id="play">Play/Pause</button>
        <button id="clear">Clear All</button>
    </div>

    <canvas id="sim"></canvas>

    <script>
        // --- Global State and Constants ---
        const canvas = document.getElementById('sim');
        const ctx = canvas.getContext('2d');

        // Set the actual drawing dimensions (must match CSS size for simplicity)
        const CANVAS_WIDTH = 400;
        const CANVAS_HEIGHT = 400;
        canvas.width = CANVAS_WIDTH;
        canvas.height = CANVAS_HEIGHT;

        let balls = [];
        let isPlaying = false;
        let animationFrameId = null;

        // Physics Constants
        const GRAVITY = 0.2; // Acceleration per step (pixels/step^2)
        const RESTITUTION = 0.85; // Energy loss factor on bounce
        const BALL_COLOR = '#f38ba8';

        /**
         * @typedef {Object} BallState
         * @property {number} x - X position (pixels)
         * @property {number} y - Y position (pixels)
         * @property {number} vx - Velocity in X direction (pixels/step)
         * @property {number} vy - Velocity in Y direction (pixels/step)
         * @property {number} r - Radius (pixels)
         */

        /**
         * Updates the position and handles collisions for a single ball.
         * @param {BallState} ball 
         * @param {number} dt Time step (unused here, but kept for API compliance).
         */
        function updateBall(ball, dt) {
            // 1. Apply Gravity
            ball.vy += GRAVITY;

            // 2. Update Position
            ball.x += ball.vx * dt;
            ball.y += ball.vy * dt;

            // 3. Collision Detection and Response (Walls)
            const r = ball.r;

            // Left/Right Walls
            if (ball.x - r < 0) {
                ball.x = r; // Clamp position
                ball.vx *= -RESTITUTION; // Reverse velocity, lose energy
            } else if (ball.x + r > CANVAS_WIDTH) {
                ball.x = CANVAS_WIDTH - r; // Clamp position
                ball.vx *= -RESTITUTION;
            }

            // Top/Bottom Walls
            if (ball.y - r < 0) {
                ball.y = r; // Clamp position
                ball.vy *= -RESTITUTION;
            } else if (ball.y + r > CANVAS_HEIGHT) {
                ball.y = CANVAS_HEIGHT - r; // Clamp position
                ball.vy *= -RESTITUTION;
            }

            // 4. Check for near-zero velocity to prevent infinite tiny movements
            if (Math.abs(ball.vx) < 0.1 && Math.abs(ball.vy) < 0.1) {
                 ball.vx = 0;
                 ball.vy = 0;
            }
        }

        /**
         * Draws all balls on the canvas.
         */
        function draw() {
            // Clear the entire canvas before drawing new frame
            ctx.clearRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

            balls.forEach(ball => {
                ctx.beginPath();
                ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
                ctx.fillStyle = BALL_COLOR;
                ctx.fill();
                ctx.strokeStyle = '#cdd6f4';
                ctx.lineWidth = 1;
                ctx.stroke();
            });
        }

        /**
         * Advances the simulation one step and redraws.
         * This function is called by both the internal loop and the API `step()`.
         * @param {number} dt Time delta (unused, but required for signature).
         */
        function simulateStep(dt) {
            // 1. Update Physics
            balls = balls.map(ball => ({ ...ball })); // Create copies to modify
            balls.forEach(ball => updateBall(ball, dt));

            // 2. Redraw
            draw();
        }


        // --- API Implementation (window.sim) ---

        /** @type {Object} */
        window.sim = {
            w: CANVAS_WIDTH,
            h: CANVAS_HEIGHT,

            /** Returns a copy of the current ball state array. */
            balls: function() {
                return balls.map(b => ({ ...b }));
            },

            /** Adds a new ball to the simulation. */
            addBall: function(x, y, vx = 0, vy = 0, r = 15) {
                // Ensure coordinates are within bounds initially
                const safeX = Math.max(r, Math.min(Math.min(CANVAS_WIDTH - r, x), CANVAS_WIDTH));
                const safeY = Math.max(r, Math.min(Math.min(CANVAS_HEIGHT - r, y), CANVAS_HEIGHT));

                balls.push({ 
                    x: safeX, 
                    y: safeY, 
                    vx: vx, 
                    vy: vy, 
                    r: r || 15 
                });
            },

            /** Removes all balls from the simulation. */
            clear: function() {
                balls = [];
                draw(); // Redraw empty canvas immediately
            },

            /** Advances the simulation one step and redraws. @param {number} dt Time delta (default 1). */
            step: function(dt = 1) {
                simulateStep(dt);
            }
        };


        // --- Animation Loop Management ---

        function gameLoop() {
            if (!isPlaying) return;

            // Run the physics step and redraw
            simulateStep(1);

            animationFrameId = requestAnimationFrame(gameLoop);
        }

        function togglePlayPause() {
            if (isPlaying) {
                cancelAnimationFrame(animationFrameId);
                isPlaying = false;
                document.getElementById('play').textContent = 'Play';
            } else {
                // Reset state if paused and starting fresh, or just continue
                gameLoop();
                isPlaying = true;
                document.getElementById('play').textContent = 'Pause';
            }
        }

        function dropRandomBall() {
            const r = Math.floor(Math.random() * 10) + 10; // Radius between 10 and 20
            // Drop near the top center, with some random horizontal velocity
            sim.addBall(CANVAS_WIDTH / 2 + (Math.random() - 0.5) * 50, 50, (Math.random() - 0.5) * 3, 0);
        }


        // --- Event Listeners and Initialization ---

        document.getElementById('drop').addEventListener('click', dropRandomBall);
        document.getElementById('play').addEventListener('click', togglePlayPause);
        document.getElementById('clear').addEventListener('click', () => {
            sim.clear();
            if (isPlaying) togglePlayPause(); // Pause if playing
        });

        // Canvas click handler: Adds a ball at the cursor position
        canvas.addEventListener('click', (e) => {
            const rect = canvas.getBoundingClientRect();
            const x = e.clientX - rect.left;
            const y = e.clientY - rect.top;

            // Add a medium-sized ball with slight initial downward velocity
            sim.addBall(x, y, 0, 1);
        });


        // Initial setup: Draw the empty canvas and set up the loop state
        window.onload = () => {
            draw(); // Draw initial state
            isPlaying = false; // Start paused
            document.getElementById('play').textContent = 'Play';
        };

    </script>
</body>
</html>
